import pandas as pd
from datetime import datetime
import matplotlib.pyplot as plt

class AccountingReport:
    def __init__(self, data, period):
        self.data = data
        self.period = period

    def generate_report(self):
        if self.period == 'month':
            return self.generate_monthly_report()
        elif self.period == 'quarter':
            return self.generate_quarterly_report()
        elif self.period == 'year':
            return self.generate_yearly_report()

    def generate_monthly_report(self):
        monthly_data = self.data.groupby(pd.Grouper(key='Date', freq='M'))['Amount'].sum().reset_index()
        return monthly_data

    def generate_quarterly_report(self):
        quarterly_data = self.data.groupby(pd.Grouper(key='Date', freq='Q'))['Amount'].sum().reset_index()
        return quarterly_data

    def generate_yearly_report(self):
        yearly_data = self.data.groupby(pd.Grouper(key='Date', freq='Y'))['Amount'].sum().reset_index()
        return yearly_data

    def plot_report(self, report_data):
        plt.figure(figsize=(10,6))
        plt.plot(report_data['Date'], report_data['Amount'], marker='o')
        plt.title('Accounting Report')
        plt.xlabel('Date')
        plt.ylabel('Amount')
        plt.show()

def retrieve_data_from_quickbooks():
    # Simulating data retrieval from QuickBooks
    data = {
        'Date': ['2022-01-01', '2022-01-15', '2022-02-01', '2022-02-15', '2022-03-01', '2022-03-15'],
        'Amount': [1000, 2000, 1500, 2500, 3000, 3500]
    }
    df = pd.DataFrame(data)
    df['Date'] = pd.to_datetime(df['Date'])
    return df

def main():
    data = retrieve_data_from_quickbooks()
    report = AccountingReport(data, 'month')
    monthly_report = report.generate_report()
    print(monthly_report)
    report.plot_report(monthly_report)

if __name__ == '__main__':
    main()

