import datetime
from dataclasses import dataclass
from enum import Enum
from typing import List

class ReportType(Enum):
    MONTHLY = 1
    QUARTERLY = 2
    YEARLY = 3

@dataclass
class Transaction:
    date: datetime.date
    amount: float
    description: str

class AccountingReport:
    def __init__(self, report_type: ReportType, start_date: datetime.date, end_date: datetime.date):
        self.report_type = report_type
        self.start_date = start_date
        self.end_date = end_date
        self.transactions = []

    def add_transaction(self, transaction: Transaction):
        if self.start_date <= transaction.date <= self.end_date:
            self.transactions.append(transaction)

    def calculate_total(self) -> float:
        return sum(transaction.amount for transaction in self.transactions)

    def calculate_tax(self, tax_rate: float) -> float:
        return self.calculate_total() * tax_rate

    def generate_report(self) -> str:
        report = f"Report for {self.report_type.name} period from {self.start_date} to {self.end_date}\n"
        report += f"Total: {self.calculate_total():.2f}\n"
        report += "Transactions:\n"
        for transaction in self.transactions:
            report += f"{transaction.date}: {transaction.amount:.2f} - {transaction.description}\n"
        return report

class AccountingSystem:
    def __init__(self):
        self.transactions = []

    def add_transaction(self, transaction: Transaction):
        self.transactions.append(transaction)

    def generate_report(self, report_type: ReportType, start_date: datetime.date, end_date: datetime.date) -> str:
        report = AccountingReport(report_type, start_date, end_date)
        for transaction in self.transactions:
            report.add_transaction(transaction)
        return report.generate_report()

def main():
    accounting_system = AccountingSystem()
    accounting_system.add_transaction(Transaction(datetime.date(2022, 1, 1), 100.0, "Sale"))
    accounting_system.add_transaction(Transaction(datetime.date(2022, 1, 15), 200.0, "Sale"))
    accounting_system.add_transaction(Transaction(datetime.date(2022, 2, 1), 50.0, "Expense"))

    report_type = ReportType.MONTHLY
    start_date = datetime.date(2022, 1, 1)
    end_date = datetime.date(2022, 1, 31)
    print(accounting_system.generate_report(report_type, start_date, end_date))

    report_type = ReportType.QUARTERLY
    start_date = datetime.date(2022, 1, 1)
    end_date = datetime.date(2022, 3, 31)
    print(accounting_system.generate_report(report_type, start_date, end_date))

