import datetime
from enum import Enum

class ReportPeriod(Enum):
    MONTH = 'month'
    QUARTER = 'quarter'
    YEAR = 'year'

class AccountingReport:
    def __init__(self, data):
        self.data = data

    def generate_report(self, period):
        if period == ReportPeriod.MONTH:
            return self._generate_monthly_report()
        elif period == ReportPeriod.QUARTER:
            return self._generate_quarterly_report()
        elif period == ReportPeriod.YEAR:
            return self._generate_yearly_report()
        else:
            raise ValueError('Invalid report period')

    def _generate_monthly_report(self):
        report = {
            'revenue': sum(self.data['monthly_revenue']),
            'expenses': sum(self.data['monthly_expenses']),
            'net_profit': sum(self.data['monthly_revenue']) - sum(self.data['monthly_expenses'])
        }
        return report

    def _generate_quarterly_report(self):
        quarterly_revenue = []
        quarterly_expenses = []
        for i in range(0, len(self.data['monthly_revenue']), 3):
            quarterly_revenue.append(sum(self.data['monthly_revenue'][i:i+3]))
            quarterly_expenses.append(sum(self.data['monthly_expenses'][i:i+3]))
        report = {
            'revenue': quarterly_revenue,
            'expenses': quarterly_expenses,
            'net_profit': [r - e for r, e in zip(quarterly_revenue, quarterly_expenses)]
        }
        return report

    def _generate_yearly_report(self):
        report = {
            'revenue': sum(self.data['monthly_revenue']),
            'expenses': sum(self.data['monthly_expenses']),
            'net_profit': sum(self.data['monthly_revenue']) - sum(self.data['monthly_expenses'])
        }
        return report

