    return {
        'monthly_revenue': [10000, 12000, 11000, 13000, 10500, 12500, 11500, 13500, 10000, 12000, 11000, 13000],
        'monthly_expenses': [5000, 6000, 5500, 6500, 5250, 6250, 5750, 6750, 5000, 6000, 5500, 6500]
    }

def main():
    data = get_accounting_data()
    report = AccountingReport(data)
    monthly_report = report.generate_report(ReportPeriod.MONTH)
    quarterly_report = report.generate_report(ReportPeriod.QUARTER)
    yearly_report = report.generate_report(ReportPeriod.YEAR)
