import datetime
import pandas as pd

class AccountingReport:
    def __init__(self, data, period):
        self.data = data
        self.period = period

    def generate_report(self):
        if self.period == 'month':
            report = self.generate_monthly_report()
        elif self.period == 'quarter':
            report = self.generate_quarterly_report()
        elif self.period == 'year':
            report = self.generate_yearly_report()
        else:
            raise ValueError('Invalid period')
        return report

    def generate_monthly_report(self):
        monthly_data = self.data[self.data['date'].dt.month == datetime.datetime.now().month]
        total_revenue = monthly_data['revenue'].sum()
        total_expenses = monthly_data['expenses'].sum()
        net_income = total_revenue - total_expenses
        return {
            'total_revenue': total_revenue,
            'total_expenses': total_expenses,
            'net_income': net_income
        }

    def generate_quarterly_report(self):
        quarterly_data = self.data[(self.data['date'].dt.month >= (datetime.datetime.now().month - (datetime.datetime.now().month % 3) + 1)) & 
                                 (self.data['date'].dt.month <= datetime.datetime.now().month)]
        total_revenue = quarterly_data['revenue'].sum()
        total_expenses = quarterly_data['expenses'].sum()
        net_income = total_revenue - total_expenses
        return {
            'total_revenue': total_revenue,
            'total_expenses': total_expenses,
            'net_income': net_income
        }

    def generate_yearly_report(self):
        yearly_data = self.data[self.data['date'].dt.year == datetime.datetime.now().year]
        total_revenue = yearly_data['revenue'].sum()
        total_expenses = yearly_data['expenses'].sum()
        net_income = total_revenue - total_expenses
        return {
            'total_revenue': total_revenue,
            'total_expenses': total_expenses,
            'net_income': net_income
        }

def get_data_from_quickbooks():
