        'date': pd.to_datetime(['2022-01-01', '2022-01-15', '2022-02-01', '2022-02-15', '2022-03-01']),
        'revenue': [1000, 2000, 1500, 2500, 3000],
        'expenses': [500, 1000, 750, 1250, 1500]
    })
    return data

