import datetime
from dataclasses import dataclass
from enum import Enum
from typing import List

class ReportPeriod(Enum):
    MONTH = 1
    QUARTER = 2
    YEAR = 3

@dataclass
class Transaction:
    date: datetime.date
    description: str
    debit: float
    credit: float

class AccountStatement:
    def __init__(self, company_name: str, report_period: ReportPeriod, start_date: datetime.date, end_date: datetime.date):
        self.company_name = company_name
        self.report_period = report_period
        self.start_date = start_date
        self.end_date = end_date
        self.transactions = []

    def add_transaction(self, transaction: Transaction):
        if self.start_date <= transaction.date <= self.end_date:
            self.transactions.append(transaction)

    def generate_report(self):
        report = f"Account Statement for {self.company_name} - {self.report_period.name}\n"
        report += f"Period: {self.start_date} to {self.end_date}\n\n"
        report += "Date\tDescription\tDebit\tCredit\n"
        for transaction in self.transactions:
            report += f"{transaction.date}\t{transaction.description}\t{transaction.debit:.2f}\t{transaction.credit:.2f}\n"
        return report

def get_report_period(period: ReportPeriod, year: int, month: int = None, quarter: int = None) -> (datetime.date, datetime.date):
    if period == ReportPeriod.MONTH:
        start_date = datetime.date(year, month, 1)
        if month == 12:
            end_date = datetime.date(year, month, 31)
        else:
            end_date = datetime.date(year, month + 1, 1) - datetime.timedelta(days=1)
    elif period == ReportPeriod.QUARTER:
        if quarter == 1:
            start_date = datetime.date(year, 1, 1)
            end_date = datetime.date(year, 3, 31)
        elif quarter == 2:
            start_date = datetime.date(year, 4, 1)
            end_date = datetime.date(year, 6, 30)
        elif quarter == 3:
            start_date = datetime.date(year, 7, 1)
            end_date = datetime.date(year, 9, 30)
        elif quarter == 4:
            start_date = datetime.date(year, 10, 1)
            end_date = datetime.date(year, 12, 31)
    elif period == ReportPeriod.YEAR:
        start_date = datetime.date(year, 1, 1)
        end_date = datetime.date(year, 12, 31)
    return start_date, end_date

def main():
    company_name = "Retail Business"
    report_period = ReportPeriod.MONTH
    year = 2024
    month = 6
    start_date, end_date = get_report_period(report_period, year, month)
    account_statement = AccountStatement(company_name, report_period, start_date, end_date)
    account_statement.add_transaction(Transaction(datetime.date(2024, 6, 1), "Sale", 0, 1000))
    account_statement.add_transaction(Transaction(datetime.date(2024, 6, 15), "Expense", 500, 0))
    print(account_statement.generate_report())

if __name__ == "__main__":
    main()

