        data = []
        for day in range(int((self.end_date - self.start_date).days) + 1):
            date = self.start_date + datetime.timedelta(days=day)
            revenue = round(random.uniform(1000, 5000), 2)
            expenses = round(random.uniform(500, 2000), 2)
            profit = revenue - expenses
            data.append({
                'date': date,
                'revenue': revenue,
                'expenses': expenses,
                'profit': profit
            })
        return data

    def get_report(self):
        total_revenue = sum(item['revenue'] for item in self.data)
        total_expenses = sum(item['expenses'] for item in self.data)
        total_profit = sum(item['profit'] for item in self.data)
        return {
            'start_date': self.start_date,
            'end_date': self.end_date,
            'total_revenue': total_revenue,
            'total_expenses': total_expenses,
            'total_profit': total_profit
        }

    def get_detailed_report(self):
        return self.data

