        end_date = datetime.date.today()
    elif period == 'year':
        start_date = datetime.date(datetime.date.today().year, 1, 1)
        end_date = datetime.date.today()
    else:
        raise ValueError('Invalid period')
    report = AccountingReport(start_date, end_date)
