import datetime
import random

class AccountingReport:
    def __init__(self, start_date, end_date):
        self.start_date = start_date
        self.end_date = end_date
        self.data = self.generate_data()

    def generate_data(self):
        data = []
        for day in self.date_range(self.start_date, self.end_date):
            data.append({
                'date': day,
                'sales': round(random.uniform(1000, 5000), 2),
                'expenses': round(random.uniform(500, 2000), 2),
                'profit': round(random.uniform(500, 3000), 2)
            })
        return data

    def date_range(self, start_date, end_date):
        dates = []
        current_date = start_date
        while current_date <= end_date:
            dates.append(current_date)
            current_date += datetime.timedelta(days=1)
        return dates

    def get_report(self):
        total_sales = sum(item['sales'] for item in self.data)
        total_expenses = sum(item['expenses'] for item in self.data)
        total_profit = sum(item['profit'] for item in self.data)
        return {
            'start_date': self.start_date,
            'end_date': self.end_date,
            'total_sales': round(total_sales, 2),
            'total_expenses': round(total_expenses, 2),
            'total_profit': round(total_profit, 2)
        }

    def get_detailed_report(self):
        return self.data

def generate_monthly_report(year, month):
    start_date = datetime.date(year, month, 1)
    if month == 12:
        end_date = datetime.date(year, month, 31)
    else:
        end_date = datetime.date(year, month + 1, 1) - datetime.timedelta(days=1)
    return AccountingReport(start_date, end_date)

def generate_quarterly_report(year, quarter):
    if quarter == 1:
        start_date = datetime.date(year, 1, 1)
        end_date = datetime.date(year, 3, 31)
    elif quarter == 2:
        start_date = datetime.date(year, 4, 1)
        end_date = datetime.date(year, 6, 30)
    elif quarter == 3:
        start_date = datetime.date(year, 7, 1)
        end_date = datetime.date(year, 9, 30)
    else:
        start_date = datetime.date(year, 10, 1)
        end_date = datetime.date(year, 12, 31)
    return AccountingReport(start_date, end_date)

def generate_yearly_report(year):
    start_date = datetime.date(year, 1, 1)
    end_date = datetime.date(year, 12, 31)
    return AccountingReport(start_date, end_date)

