        if period == 'month':
            return self.generate_monthly_report()
        elif period == 'quarter':
            return self.generate_quarterly_report()
        elif period == 'year':
            return self.generate_yearly_report()
        else:
            raise ValueError('Invalid period')

    def generate_monthly_report(self):
        current_month = datetime.date.today().month
        current_year = datetime.date.today().year
        monthly_data = self.data[(self.data['date'].dt.month == current_month) & (self.data['date'].dt.year == current_year)]
        return self.calculate_report(monthly_data)

    def generate_quarterly_report(self):
        current_quarter = (datetime.date.today().month - 1) // 3 + 1
        current_year = datetime.date.today().year
        quarterly_data = self.data[(self.data['date'].dt.year == current_year) & ((self.data['date'].dt.month - 1) // 3 + 1 == current_quarter)]
        return self.calculate_report(quarterly_data)

    def generate_yearly_report(self):
        current_year = datetime.date.today().year
        yearly_data = self.data[self.data['date'].dt.year == current_year]
        return self.calculate_report(yearly_data)

    def calculate_report(self, data):
        total_revenue = data['revenue'].sum()
        total_expenses = data['expenses'].sum()
        net_income = total_revenue - total_expenses
        return {
            'total_revenue': total_revenue,
            'total_expenses': total_expenses,
            'net_income': net_income
        }

