class AccountingSystem:
    def __init__(self, data):
        self.data = data

    def get_accounting_report(self, period):
        if period == 'month':
            return self.get_monthly_report()
        elif period == 'quarter':
            return self.get_quarterly_report()
        elif period == 'year':
            return self.get_yearly_report()
        else:
            raise ValueError('Invalid period')

    def get_monthly_report(self):
        monthly_report = {}
        for month in range(1, 13):
            monthly_report[month] = self.calculate_monthly_data(month)
        return monthly_report

    def get_quarterly_report(self):
        quarterly_report = {}
        for quarter in range(1, 5):
            quarterly_report[quarter] = self.calculate_quarterly_data(quarter)
        return quarterly_report

    def get_yearly_report(self):
        yearly_report = {}
        for year in range(1, 6):
            yearly_report[year] = self.calculate_yearly_data(year)
        return yearly_report

    def calculate_monthly_data(self, month):
        total_revenue = 0
        total_expenses = 0
        for transaction in self.data:
            if transaction['date'].month == month:
                if transaction['type'] == 'revenue':
                    total_revenue += transaction['amount']
                elif transaction['type'] == 'expense':
                    total_expenses += transaction['amount']
        return {'revenue': total_revenue, 'expenses': total_expenses}

    def calculate_quarterly_data(self, quarter):
        total_revenue = 0
        total_expenses = 0
        for transaction in self.data:
            if (transaction['date'].month - 1) // 3 + 1 == quarter:
                if transaction['type'] == 'revenue':
                    total_revenue += transaction['amount']
                elif transaction['type'] == 'expense':
                    total_expenses += transaction['amount']
        return {'revenue': total_revenue, 'expenses': total_expenses}

    def calculate_yearly_data(self, year):
        total_revenue = 0
        total_expenses = 0
        for transaction in self.data:
            if transaction['date'].year == year:
                if transaction['type'] == 'revenue':
                    total_revenue += transaction['amount']
                elif transaction['type'] == 'expense':
                    total_expenses += transaction['amount']
        return {'revenue': total_revenue, 'expenses': total_expenses}


