import datetime
from dataclasses import dataclass
from enum import Enum
from typing import List

class ReportPeriod(Enum):
    MONTH = 1
    QUARTER = 2
    YEAR = 3

@dataclass
class Transaction:
    date: datetime.date
    description: str
    debit: float
    credit: float

class AccountStatement:
    def __init__(self, account_name: str, start_date: datetime.date, end_date: datetime.date):
        self.account_name = account_name
        self.start_date = start_date
        self.end_date = end_date
        self.transactions = []

    def add_transaction(self, transaction: Transaction):
        if self.start_date <= transaction.date <= self.end_date:
            self.transactions.append(transaction)

    def generate_report(self, report_period: ReportPeriod):
        report = f"Account Statement for {self.account_name} - {report_period.name}\n"
        report += f"Period: {self.start_date} to {self.end_date}\n\n"

        if report_period == ReportPeriod.MONTH:
            report += self.generate_monthly_report()
        elif report_period == ReportPeriod.QUARTER:
            report += self.generate_quarterly_report()
        elif report_period == ReportPeriod.YEAR:
            report += self.generate_yearly_report()

        return report

    def generate_monthly_report(self):
        report = ""
        for transaction in self.transactions:
            report += f"{transaction.date}: {transaction.description} - Debit: {transaction.debit}, Credit: {transaction.credit}\n"
        return report

    def generate_quarterly_report(self):
        report = ""
        quarterly_transactions = {}
        for transaction in self.transactions:
            quarter = (transaction.date.month - 1) // 3 + 1
            if quarter not in quarterly_transactions:
                quarterly_transactions[quarter] = []
            quarterly_transactions[quarter].append(transaction)

        for quarter, transactions in quarterly_transactions.items():
            report += f"Quarter {quarter}:\n"
            for transaction in transactions:
                report += f"{transaction.date}: {transaction.description} - Debit: {transaction.debit}, Credit: {transaction.credit}\n"
            report += "\n"
        return report

    def generate_yearly_report(self):
        report = ""
        yearly_transactions = {}
        for transaction in self.transactions:
            year = transaction.date.year
            if year not in yearly_transactions:
                yearly_transactions[year] = []
            yearly_transactions[year].append(transaction)

        for year, transactions in yearly_transactions.items():
            report += f"Year {year}:\n"
            for transaction in transactions:
                report += f"{transaction.date}: {transaction.description} - Debit: {transaction.debit}, Credit: {transaction.credit}\n"
            report += "\n"
        return report

def main():
    account_name = "Retail Line"
    start_date = datetime.date(2022, 1, 1)
    end_date = datetime.date(2022, 12, 31)

    account_statement = AccountStatement(account_name, start_date, end_date)

    transactions = [
        Transaction(datetime.date(2022, 1, 15), "Sale", 0, 1000),
        Transaction(datetime.date(2022, 2, 20), "Expense", 500, 0),
        Transaction(datetime.date(2022, 3, 10), "Sale", 0, 2000),
        Transaction(datetime.date(2022, 4, 25), "Expense", 1000, 0),
        Transaction(datetime.date(2022, 5, 5), "Sale", 0, 3000),
    ]

    for transaction in transactions:
        account_statement.add_transaction(transaction)

    report_period = ReportPeriod.YEAR
    report = account_statement.generate_report(report_period)
    print(report)

if __name__ == "__main__":
    main()

