class AccountingStory:
    def __init__(self, start_date, end_date, data):
        self.start_date = start_date
        self.end_date = end_date
        self.data = data

    def generate_story(self):
        story = ""
        story += f"Accounting Story for {self.start_date.strftime('%B %Y')} to {self.end_date.strftime('%B %Y')}\n"
        story += "--------------------------------------------------------\n"
        story += f"Total Revenue: ${self.get_total_revenue():.2f}\n"
        story += f"Total Expenses: ${self.get_total_expenses():.2f}\n"
        story += f"Net Income: ${self.get_net_income():.2f}\n"
        story += "--------------------------------------------------------\n"
        story += "Revenue Breakdown:\n"
        for category, amount in self.get_revenue_breakdown():
            story += f"- {category}: ${amount:.2f}\n"
        story += "--------------------------------------------------------\n"
        story += "Expense Breakdown:\n"
        for category, amount in self.get_expense_breakdown():
            story += f"- {category}: ${amount:.2f}\n"
        return story

    def get_total_revenue(self):
        return sum([entry['revenue'] for entry in self.data])

    def get_total_expenses(self):
        return sum([entry['expenses'] for entry in self.data])

    def get_net_income(self):
        return self.get_total_revenue() - self.get_total_expenses()

    def get_revenue_breakdown(self):
        breakdown = {}
        for entry in self.data:
            for category, amount in entry['revenue_breakdown'].items():
                if category in breakdown:
                    breakdown[category] += amount
                else:
                    breakdown[category] = amount
        return breakdown.items()

    def get_expense_breakdown(self):
        breakdown = {}
        for entry in self.data:
            for category, amount in entry['expense_breakdown'].items():
                if category in breakdown:
                    breakdown[category] += amount
                else:
                    breakdown[category] = amount
        return breakdown.items()

