                    start_date = datetime.date(year, 10, 1)
                    end_date = datetime.date(year, 12, 31)
                reports.append(self.generate_report(period, start_date, end_date))
            return reports
        elif period == ReportPeriod.YEAR:
            start_date = datetime.date(year, 1, 1)
            end_date = datetime.date(year, 12, 31)
            return self.generate_report(period, start_date, end_date)

