        report = {}
        for month in range(1, 13):
            report[f'Month {month}'] = self.calculate_monthly_data(month)
        return report

    def generate_quarterly_report(self):
        report = {}
        for quarter in range(1, 5):
            report[f'Quarter {quarter}'] = self.calculate_quarterly_data(quarter)
        return report

    def generate_annually_report(self):
        report = {}
        report['Annual'] = self.calculate_annually_data()
        return report

