        monthly_data = [data for data in self.data if data['date'].month == month]
        return self.calculate_total_revenue(monthly_data), self.calculate_total_expense(monthly_data)

    def calculate_quarterly_data(self, quarter):
        quarterly_data = [data for data in self.data if (data['date'].month - 1) // 3 + 1 == quarter]
        return self.calculate_total_revenue(quarterly_data), self.calculate_total_expense(quarterly_data)

    def calculate_annually_data(self):
        return self.calculate_total_revenue(self.data), self.calculate_total_expense(self.data)

