        monthly_data = {}
        for date, value in data.items():
            month = date.strftime('%Y-%m')
            if month not in monthly_data:
                monthly_data[month] = 0
            monthly_data[month] += value
        return monthly_data

    def generate_quarterly_report(self, data):
        quarterly_data = {}
        for date, value in data.items():
            quarter = f"{date.year}-Q{self.get_quarter(date.month)}"
            if quarter not in quarterly_data:
                quarterly_data[quarter] = 0
            quarterly_data[quarter] += value
        return quarterly_data

    def generate_annually_report(self, data):
        annually_data = {}
        for date, value in data.items():
            year = date.year
            if year not in annually_data:
                annually_data[year] = 0
            annually_data[year] += value
        return annually_data

