            'invoices': invoices,
            'payments': payments,
            'total_revenue': sum(invoice['amount'] for invoice in invoices),
            'total_expenses': sum(payment['amount'] for payment in payments)
        }
        return report

    def get_sage_report(self):
        # Connect to Sage API
        import sage
        client = sage.Client()
        client.authorize()

        # Get data from Sage
        invoices = client.get_invoices(self.start_date, self.end_date)
        payments = client.get_payments(self.start_date, self.end_date)

        # Generate report
        report = {
            'invoices': invoices,
            'payments': payments,
            'total_revenue': sum(invoice['amount'] for invoice in invoices),
            'total_expenses': sum(payment['amount'] for payment in payments)
        }
        return report

    def customize_report(self, time_period):
        if time_period == 'calendar month':
            self.start_date = self.start_date.replace(day=1)
            self.end_date = self.end_date.replace(day=1)
        elif time_period == 'quarter':
            quarter = (self.start_date.month - 1) // 3 + 1
            self.start_date = self.start_date.replace(month=(quarter - 1) * 3 + 1, day=1)
            self.end_date = self.end_date.replace(month=quarter * 3, day=1)
        elif time_period == 'year':
            self.start_date = self.start_date.replace(month=1, day=1)
            self.end_date = self.end_date.replace(month=12, day=31)
        else:
            raise ValueError('Invalid time period')

