        quickbooks_data = self.get_quickbooks_data()
        report_data = self.process_monthly_data(quickbooks_data)
        return report_data

    def generate_quarterly_report(self):
        # Assume data is coming from QuickBooks
        quickbooks_data = self.get_quickbooks_data()
        report_data = self.process_quarterly_data(quickbooks_data)
        return report_data

    def generate_yearly_report(self):
