            'November': {'revenue': 3500, 'expenses': 1500},
            'December': {'revenue': 3800, 'expenses': 1600}
        }
        return data

    def process_monthly_data(self, data):
        report_data = {}
        for month, values in data.items():
            revenue = values['revenue']
            expenses = values['expenses']
            profit = revenue - expenses
            report_data[month] = {'revenue': revenue, 'expenses': expenses, 'profit': profit}
        return report_data

    def process_quarterly_data(self, data):
        report_data = {}
        quarters = {
            'Q1': ['January', 'February', 'March'],
            'Q2': ['April', 'May', 'June'],
            'Q3': ['July', 'August', 'September'],
            'Q4': ['October', 'November', 'December']
        }
        for quarter, months in quarters.items():
            total_revenue = 0
            total_expenses = 0
            for month in months:
                total_revenue += data[month]['revenue']
                total_expenses += data[month]['expenses']
            total_profit = total_revenue - total_expenses
            report_data[quarter] = {'revenue': total_revenue, 'expenses': total_expenses, 'profit': total_profit}
        return report_data

    def process_yearly_data(self, data):
        total_revenue = 0
        total_expenses = 0
        for month, values in data.items():
            total_revenue += values['revenue']
            total_expenses += values['expenses']
        total_profit = total_revenue - total_expenses
        return {'revenue': total_revenue, 'expenses': total_expenses, 'profit': total_profit}

