class SpiritualistSizingRetailBusiness:
    def __init__(self, name, start_date, end_date):
        self.name = name
        self.start_date = start_date
        self.end_date = end_date
        self.accounts = {}

    def add_account(self, account_name, account_type, initial_balance):
        self.accounts[account_name] = {'type': account_type, 'balance': initial_balance}

    def debit(self, account_name, amount):
        if account_name in self.accounts:
            self.accounts[account_name]['balance'] -= amount
        else:
            print("Account not found")

    def credit(self, account_name, amount):
        if account_name in self.accounts:
            self.accounts[account_name]['balance'] += amount
        else:
            print("Account not found")

    def get_balance(self, account_name):
        if account_name in self.accounts:
            return self.accounts[account_name]['balance']
        else:
            print("Account not found")

    def generate_report(self, period):
        if period == 'month':
            start_date = self.start_date
            end_date = self.end_date
        elif period == 'quarter':
            start_date = self.start_date
            end_date = self.end_date
        elif period == 'year':
            start_date = self.start_date
            end_date = self.end_date
        else:
            print("Invalid period")

        print("Report for", self.name, "from", start_date, "to", end_date)
        for account, details in self.accounts.items():
            print(account, ":", details['balance'])

    def import_data(self, file_name):
        import csv
        with open(file_name, 'r') as file:
            reader = csv.reader(file)
            for row in reader:
                account_name = row[0]
                account_type = row[1]
                initial_balance = float(row[2])
                self.add_account(account_name, account_type, initial_balance)

    def export_data(self, file_name):
        import csv
        with open(file_name, 'w', newline='') as file:
            writer = csv.writer(file)
            for account, details in self.accounts.items():
                writer.writerow([account, details['type'], details['balance']])


