class AccountStatement:
    def __init__(self, data):
        self.data = data

    def get_balance(self, date):
        balance = 0
        for entry in self.data:
            if entry['date'] <= date:
                if entry['type'] == 'debit':
                    balance -= entry['amount']
                elif entry['type'] == 'credit':
                    balance += entry['amount']
        return balance

    def get_income_statement(self, start_date, end_date):
        income = 0
        expenses = 0
        for entry in self.data:
            if start_date <= entry['date'] <= end_date:
                if entry['type'] == 'credit':
                    income += entry['amount']
                elif entry['type'] == 'debit':
                    expenses += entry['amount']
        return income, expenses

    def get_customizable_report(self, period):
        if period == 'month':
            start_date = self.get_start_of_month()
            end_date = self.get_end_of_month()
        elif period == 'quarter':
            start_date = self.get_start_of_quarter()
            end_date = self.get_end_of_quarter()
        elif period == 'year':
            start_date = self.get_start_of_year()
            end_date = self.get_end_of_year()
        else:
            raise ValueError('Invalid period')

        income, expenses = self.get_income_statement(start_date, end_date)
        balance = self.get_balance(end_date)
        return income, expenses, balance

    def get_start_of_month(self):
        return self.data[0]['date'].replace(day=1)

    def get_end_of_month(self):
        return self.data[0]['date'].replace(day=28)

    def get_start_of_quarter(self):
        quarter = (self.data[0]['date'].month - 1) // 3 + 1
        return self.data[0]['date'].replace(month=(quarter - 1) * 3 + 1, day=1)

    def get_end_of_quarter(self):
        quarter = (self.data[0]['date'].month - 1) // 3 + 1
        if quarter == 1:
            return self.data[0]['date'].replace(month=3, day=31)
        elif quarter == 2:
            return self.data[0]['date'].replace(month=6, day=30)
        elif quarter == 3:
            return self.data[0]['date'].replace(month=9, day=30)
        elif quarter == 4:
            return self.data[0]['date'].replace(month=12, day=31)

    def get_start_of_year(self):
        return self.data[0]['date'].replace(month=1, day=1)

    def get_end_of_year(self):
        return self.data[0]['date'].replace(month=12, day=31)


